  const maxRequests = options.maxRequests != null ? options.maxRequests : 100;
  const cleanupIntervalMs =
    options.cleanupIntervalMs != null ? options.cleanupIntervalMs : 60000;
  const keyGenerator =
    options.keyGenerator ||
    ((req) => req.ip || (req.socket && req.socket.remoteAddress) || 'unknown');

  if (!Number.isFinite(windowMs) || windowMs <= 0) {
    throw new TypeError('windowMs must be a positive number');
  }
  if (!Number.isFinite(maxRequests) || maxRequests <= 0) {
    throw new TypeError('maxRequests must be a positive number');
  }

  // Map<clientKey, number[]> -> array of request timestamps (ms epoch), ascending.
  const hits = new Map();

  /**
   * Drop every timestamp at or before `cutoff` from a sorted-ascending array.
   * Timestamps are pushed in chronological order, so we just find the first
   * index still inside the window and slice from there.
   */
  function pruneOlderThan(timestamps, cutoff) {
    let i = 0;
    while (i < timestamps.length && timestamps[i] <= cutoff) {
      i++;
    }
    return i === 0 ? timestamps : timestamps.slice(i);
  }

  const middleware = function rateLimiter(req, res, next) {
    const now = Date.now();
    const cutoff = now - windowMs;
    const key = keyGenerator(req);

    // 1. Remove all timestamps older than the window from "now".
    let timestamps = hits.get(key) || [];
    timestamps = pruneOlderThan(timestamps, cutoff);

    // 2. Count what remains. If at/over the limit -> reject.
    if (timestamps.length >= maxRequests) {
      // Persist the pruned list so the window keeps sliding for this client.
      hits.set(key, timestamps);

      // The oldest in-window request is what frees a slot when it expires.
      const oldest = timestamps[0];
      const resetMs = oldest + windowMs;          // when a slot next opens
      const retryAfterSec = Math.max(1, Math.ceil((resetMs - now) / 1000));

      res.setHeader('X-RateLimit-Limit', maxRequests);
      res.setHeader('X-RateLimit-Remaining', 0);
      res.setHeader('X-RateLimit-Reset', Math.ceil(resetMs / 1000));
      res.setHeader('Retry-After', retryAfterSec);

