    timestamps.push(now);
    hits.set(key, timestamps);

    const remaining = maxRequests - timestamps.length;
    // Window (for this client) fully resets when the current oldest hit expires.
    const resetMs = timestamps[0] + windowMs;

    res.setHeader('X-RateLimit-Limit', maxRequests);
    res.setHeader('X-RateLimit-Remaining', remaining);
    res.setHeader('X-RateLimit-Reset', Math.ceil(resetMs / 1000));

    next();
  };

  // ---- Memory management: periodically evict IPs with no in-window hits. ----
  const cleanupTimer = setInterval(() => {
    const cutoff = Date.now() - windowMs;
    for (const [key, timestamps] of hits) {
      const pruned = pruneOlderThan(timestamps, cutoff);
