/**
 * slidingWindowRateLimiter.js
 *
 * True sliding window rate limiting middleware for Express.js.
 *
 * Unlike a fixed-window counter (which resets on a schedule), a sliding window
 * anchors to *now*: on every request we look back exactly `windowMs` milliseconds
 * and count only the hits that fall inside that rolling range.  This prevents the
 * classic burst exploit where a client sends `maxRequests` at 00:59 and another
 * `maxRequests` at 01:01 — both batches within the same 2-second span yet allowed
 * by a fixed-window implementation.
 *
 * ─────────────────────────────────────────────────────────────────────────────
 * PROXY / req.ip NOTE
 * ─────────────────────────────────────────────────────────────────────────────
 * Express sets `req.ip` from the TCP socket address by default.  When your app
 * sits behind a reverse proxy (Nginx, AWS ALB, Cloudflare, etc.) every request
 * appears to come from the proxy's IP, so all clients share a single bucket.
 *
 * Fix — tell Express to trust the proxy chain *before* registering this middleware:
 *
 *   app.set('trust proxy', 1);   // trust first hop (e.g. Nginx on the same host)
 *
 * With trust proxy enabled, Express reads X-Forwarded-For and sets req.ip to the
 * real client address.  Only enable as many hops as you actually control; spoofing
 * is possible if you trust too many.
 * ─────────────────────────────────────────────────────────────────────────────
 */

"use strict";

/**
 * Creates a sliding-window rate limiter.
 *
 * @param {object}   [options]
 * @param {number}   [options.windowMs=60000]   - Rolling window size in milliseconds.
 * @param {number}   [options.maxRequests=100]  - Maximum requests allowed per window.
 * @param {Function} [options.keyGenerator]     - (req) => string  Override the IP key.
 * @param {Function} [options.onLimitReached]   - (req, res, opts) => bool  Custom 429 hook.
 *                                                Return true to suppress the default response.
 * @returns {{ middleware: Function, close: Function, resetKey: Function }}
 */
function createRateLimiter(options = {}) {

  // ── Configuration ─────────────────────────────────────────────────────────
  const windowMs    = typeof options.windowMs    === "number" ? options.windowMs    : 60_000;
  const maxRequests = typeof options.maxRequests === "number" ? options.maxRequests : 100;

  if (windowMs    <= 0) throw new RangeError("windowMs must be a positive number");
  if (maxRequests <= 0) throw new RangeError("maxRequests must be a positive number");

  const keyGenerator = typeof options.keyGenerator === "function"
    ? options.keyGenerator
    : (req) => req.ip ?? "unknown";

  const onLimitReached = typeof options.onLimitReached === "function"
    ? options.onLimitReached
    : null;

  // ── Storage ───────────────────────────────────────────────────────────────
  // Map<clientKey, number[]>
  // Each value is a sorted (ascending) array of hit timestamps in epoch-ms.
  // Sorted order is guaranteed because we always append `Date.now()` — which
  // is monotonically non-decreasing — so no explicit sort is ever needed.
  /** @type {Map<string, number[]>} */
  const store = new Map();

  // ── Background cleanup ────────────────────────────────────────────────────
  // Sweeps the store every 60 s.  Removes entries whose entire timestamp array
  // has fallen outside the window, preventing unbounded memory growth from
  // one-off visitors (crawlers, port scanners, etc.).
  const cleanupTimer = setInterval(() => {
    const cutoff = Date.now() - windowMs;
    for (const [key, timestamps] of store) {
      const alive = dropExpired(timestamps, cutoff);
      if (alive.length === 0) {
        store.delete(key);    // No recent activity — free the entry entirely.
      } else {
        store.set(key, alive);
      }
    }
  }, 60_000);

  // Unref lets the Node.js event loop exit naturally without explicitly calling
  // close().  close() is still provided for test teardown / graceful shutdown.
  if (cleanupTimer.unref) cleanupTimer.unref();

  // ── Helpers ───────────────────────────────────────────────────────────────

  /**
   * Returns the sub-array of timestamps that are strictly after `cutoff`.
   *
   * Uses binary search on the sorted array: O(log n) scan + O(k) slice,
   * where k is the number of timestamps kept.  Much faster than Array#filter
   * for high-traffic IPs with large timestamp histories.
   *
   * @param {number[]} timestamps - Sorted ascending array of epoch-ms values.
   * @param {number}   cutoff     - Drop entries where timestamp <= cutoff.
   * @returns {number[]}
   */
  function dropExpired(timestamps, cutoff) {
    let lo = 0, hi = timestamps.length;
    while (lo < hi) {
      const mid = (lo + hi) >>> 1;
      if (timestamps[mid] <= cutoff) lo = mid + 1;
      else hi = mid;
    }
    // lo is now the index of the first timestamp that belongs in the window.
    return lo === 0 ? timestamps : timestamps.slice(lo);
  }

  // ── Middleware ────────────────────────────────────────────────────────────

  /**
   * Express middleware — the sliding window algorithm runs here.
   *
   * Per-request steps:
   *  1. Resolve the client key (IP by default).
   *  2. Compute window boundary: cutoff = now - windowMs.
   *  3. Evict all timestamps ≤ cutoff from the stored array.
   *  4. Count remaining (in-window) timestamps.
   *  5a. count >= maxRequests → 429, set Retry-After, do NOT call next().
   *  5b. count <  maxRequests → append timestamp, set headers, call next().
   */
  function middleware(req, res, next) {
    const now    = Date.now();
    const cutoff = now - windowMs;

    const key        = keyGenerator(req);
    const raw        = store.get(key) ?? [];
    const timestamps = dropExpired(raw, cutoff);  // live hits in this window
    const hitCount   = timestamps.length;

    if (hitCount >= maxRequests) {
      // ── Rejected (429) ────────────────────────────────────────────────────
      // The oldest hit inside the window is timestamps[0].
      // Once it slides out (oldest + windowMs), the count drops below the cap.
      const oldestHit     = timestamps[0];
      const retryAfterMs  = (oldestHit + windowMs) - now;
      const retryAfterSec = Math.ceil(retryAfterMs / 1000);

      // Persist the evicted-but-not-extended array so the window keeps sliding
      // correctly for subsequent probes during the blocked period.
      store.set(key, timestamps);

      res.set("Retry-After", String(retryAfterSec));

      if (onLimitReached) {
        const handled = onLimitReached(req, res, { windowMs, maxRequests, retryAfterSec });
        if (handled) return;  // Caller owns the response — bail out.
      }

      return res.status(429).json({
        error: "Rate limit exceeded",
        retryAfter: retryAfterSec,
      });
    }

    // ── Allowed ───────────────────────────────────────────────────────────
    // Append the current timestamp.  Because `now` >= every prior value,
    // the array stays sorted without any additional work.
    const updated   = timestamps.concat(now);
    store.set(key, updated);

    const remaining     = maxRequests - updated.length;              // always >= 0
    const resetEpochSec = Math.ceil((now + windowMs) / 1000);       // earliest full expiry

    res.set({
      "X-RateLimit-Limit":     String(maxRequests),
      "X-RateLimit-Remaining": String(remaining),
      "X-RateLimit-Reset":     String(resetEpochSec),
    });

    return next();
  }

  // ── Public API ────────────────────────────────────────────────────────────

  /** Stop the cleanup timer — call during graceful shutdown or test teardown. */
  function close() {
    clearInterval(cleanupTimer);
  }

  /**
   * Clear the rate-limit window for a specific key (admin override / test reset).
   * @param {string} key - The value your keyGenerator returns for that client.
   */
  function resetKey(key) {
    store.delete(key);
  }

  return { middleware, close, resetKey };
}

module.exports = { createRateLimiter };
