   * @param {import('express').Request} req
   * @param {import('express').Response} res
   * @param {import('express').NextFunction} next
   */
  function rateLimitMiddleware(req, res, next) {
    // Resolve client identifier.
    // Prefer req.ip (populated by Express after trust-proxy processing).
    let ip = req.ip;

    if (!ip) {
      // Manual extraction (common when trust proxy is not configured or in tests)
      const forwarded = req.headers && (req.headers['x-forwarded-for'] || req.headers['x-real-ip']);
      if (forwarded) {
        ip = String(forwarded).split(',')[0].trim();
      }
    }

    if (!ip) {
      ip = (req.connection && req.connection.remoteAddress) ||
           (req.socket && req.socket.remoteAddress) ||
           'unknown';
    }

    ip = String(ip).trim();

    const now = Date.now();
    const cutoff = now - windowMs;

    // Retrieve (or initialize) the list of timestamps for this IP
    let timestamps = requests.get(ip) || [];

    // === TRUE SLIDING WINDOW PRUNING ===
    // Remove every timestamp that is older than (now - windowMs).
    // This is the heart of the algorithm: the window "slides" continuously
    // with wall-clock time rather than resetting on a fixed schedule.
    timestamps = timestamps.filter(ts => ts > cutoff);

    // Check against the limit using the *current* count of still-valid requests.
    if (timestamps.length >= maxRequests) {
      // Compute how long the caller must wait until the oldest request falls
      // out of the window, freeing up one slot.
      const oldest = timestamps[0];
      const retryAfterMs = (oldest + windowMs) - now;
      const retryAfter = Math.max(1, Math.ceil(retryAfterMs / 1000));

      res.set('Retry-After', String(retryAfter));

      return res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter
      });
    }

    // Request is allowed: record the current timestamp
    timestamps.push(now);
    requests.set(ip, timestamps);

    // === Rate limit response headers (only set on successful/allowed requests) ===
    res.set('X-RateLimit-Limit', String(maxRequests));

    // Remaining quota after this request has been counted.
    const remaining = maxRequests - timestamps.length;
    res.set('X-RateLimit-Remaining', String(remaining));

    // X-RateLimit-Reset: Unix epoch seconds when the oldest request in the
    // current window will expire (i.e. the moment the count will drop by one).
    const resetEpochSec = Math.ceil((timestamps[0] + windowMs) / 1000);
    res.set('X-RateLimit-Reset', String(resetEpochSec));

    next();
  }

  // Expose the cleanup method directly on the middleware function.
  rateLimitMiddleware.close = close;

  // Exposed for testing / introspection only (not part of public API)
  rateLimitMiddleware._store = requests;

  return rateLimitMiddleware;
}

module.exports = {
  createRateLimiter
};
```

## Brief usage example

```javascript
const express = require('express');
const { createRateLimiter } = require('./rate-limiter');

const app = express();

// CRITICAL: Configure trust proxy *before* using any IP-based middleware.
app.set('trust proxy', 1);

const limiter = createRateLimiter({
  windowMs: 60 * 1000,   // 1 minute sliding window
  maxRequests: 100
});

// Apply globally or to specific routes
app.use('/api', limiter);

app.get('/api/data', (req, res) => {
  res.json({ ok: true });
});

const server = app.listen(3000, () => {
  console.log('Server started');
});

// On graceful shutdown (important for the timer)
function shutdown() {
  console.log('Shutting down...');
  limiter.close();                    // stops the cleanup interval
  server.close(() => process.exit(0));
}

process.on('SIGTERM', shutdown);
process.on('SIGINT', shutdown);
```

The implementation was verified to correctly:
- Enforce a true sliding window (timestamps pruned on every request)
- Return correct `X-RateLimit-*` headers and `Retry-After`
- Produce the exact 429 JSON body
- Clean up idle IPs and expose `close()` to stop the interval
